// mm/src/steps/previewStage.js
import React, { useMemo, useState } from 'react';
import { useWorkflow } from '../store/workflowContext';

// Fallback sample used ONLY if no uploaded text exists
const FALLBACK_TEXT = [
  'In the quiet town of Millbrook, where autumn leaves danced through cobblestone streets and the scent of fresh bread wafted from corner bakeries, something remarkable was about to unfold.',
  'Margaret closed her weathered journal, its pages filled with decades of dreams and observations. Today marked the beginning of a new chapter—not just in her writing, but in her life.',
  '"Every story begins with a single word," she whispered to herself, pen hovering over a fresh page. "And every word carries the weight of possibility."',
].join(' ');

// Approximate characters per page depending on trim
function getCharsPerPage(trim) {
  const t = (trim || '').toLowerCase();
  if (t.includes('6x9')) return 1150;
  if (t.includes('5x8')) return 900;
  if (t.includes('5.5x8.5')) return 1000;
  return 1000;
}

// Naive pagination: split text into chunks at word boundaries
function chunkTextToPages(text, charsPerPage) {
  const cleaned = (text || '').replace(/\s+/g, ' ').trim();
  if (!cleaned) return [];

  const pages = [];
  let start = 0;

  while (start < cleaned.length) {
    let end = start + charsPerPage;
    if (end >= cleaned.length) {
      pages.push(cleaned.slice(start).trim());
      break;
    }
    let lastSpace = cleaned.lastIndexOf(' ', end);
    if (lastSpace <= start + 200) lastSpace = end;
    pages.push(cleaned.slice(start, lastSpace).trim());
    start = lastSpace + 1;
  }

  return pages;
}

function Page({ page, align = 'left' }) {
  const base =
    'w-1/2 h-[420px] bg-slate-50 border border-slate-200 flex flex-col px-12 py-12';

  if (!page) {
    return <div className={`${base} rounded-lg`} />;
  }

  if (page.type === 'title') {
    return (
      <div
        className={`${base} rounded-lg`}
        style={{ justifyContent: 'center', alignItems: 'center' }}
      >
        <div className="text-center">
          <div className="text-3xl font-serif font-semibold mb-4">
            {page.title}
          </div>
          <div className="text-[11px] uppercase tracking-[0.18em] text-slate-400">
            by
          </div>
          <div className="text-base text-slate-600 mt-1">{page.author}</div>
        </div>
      </div>
    );
  }

  return (
    <div
      className={`${base} rounded-lg ${
        align === 'right'
          ? 'border-l-0 rounded-l-none'
          : 'border-r-0 rounded-r-none'
      }`}
    >
      <div className="text-[15px] leading-relaxed text-slate-800">
        {page.text}
      </div>
    </div>
  );
}

function Spread({ leftPage, rightPage }) {
  return (
    <div className="relative max-w-4xl mx-auto mt-8 mb-8 flex shadow-[0_24px_60px_rgba(15,23,42,0.24)] rounded-xl overflow-hidden bg-white">
      <Page page={leftPage} align="left" />
      <Page page={rightPage} align="right" />
      <div className="absolute inset-y-6 left-1/2 w-px bg-slate-200" />
    </div>
  );
}

const PreviewStep = () => {
  const { bookDetails = {}, design = {}, previewText } = useWorkflow();

  const title = bookDetails.title || 'Your Book Title';
  const author = bookDetails.author || 'Author Name';
  const trim = design.trim || '6x9';
  const typography = (design.typography || 'hybrid').toLowerCase();
  const layout = (design.layout || 'standard').toLowerCase();

  const charsPerPage = getCharsPerPage(trim);

  const pages = useMemo(() => {
    const source =
      previewText && previewText.trim() ? previewText : FALLBACK_TEXT;

    const contentPages = chunkTextToPages(source, charsPerPage).map((t) => ({
      type: 'content',
      text: t,
    }));

    const titlePages = [
      { type: 'title', title, author },
      { type: 'title', title, author },
    ];

    return [...titlePages, ...contentPages];
  }, [previewText, title, author, charsPerPage]);

  const [pageIndex, setPageIndex] = useState(0); // left page index

  const totalPages = pages.length || 1;
  const totalSpreads = Math.ceil(totalPages / 2);
  const spreadIndex = Math.floor(pageIndex / 2);

  const leftPage = pages[pageIndex] || null;
  const rightPage = pages[pageIndex + 1] || null;

  const canPrev = spreadIndex > 0;
  const canNext = spreadIndex < totalSpreads - 1;

  const handlePrev = () => {
    if (!canPrev) return;
    const newSpread = spreadIndex - 1;
    setPageIndex(newSpread * 2);
  };

  const handleNext = () => {
    if (!canNext) return;
    const newSpread = spreadIndex + 1;
    setPageIndex(newSpread * 2);
  };

  const progress = Math.round(((spreadIndex + 1) / totalSpreads) * 100);

  return (
    <div className="bg-white rounded-2xl shadow-sm p-6">
      {/* Tabs */}
      <div className="flex items-center gap-2 mb-6">
        <button className="flex-1 text-xs md:text-sm px-3 py-2 rounded-md bg-slate-900 text-white font-medium">
          KDP Paperback
        </button>
        <button className="flex-1 text-xs md:text-sm px-3 py-2 rounded-md bg-slate-100 text-slate-500">
          Apple Books EPUB
        </button>
        <button className="flex-1 text-xs md:text-sm px-3 py-2 rounded-md bg-slate-100 text-slate-500">
          IngramSpark Print
        </button>
      </div>

      <div className="px-2 md:px-6 pb-4">
        <div className="flex items-center justify-between mb-2">
          <div className="text-lg font-semibold">KDP Preview</div>
          <div className="inline-flex items-center gap-1 px-2 py-0.5 rounded-full bg-emerald-50 text-emerald-700 border border-emerald-100 text-[11px]">
            <span className="w-1.5 h-1.5 rounded-full bg-emerald-500" />
            Platform Ready
          </div>
        </div>

        <div className="flex items-center justify-center text-xs text-slate-500 mb-1">
          <span className="mr-1">📖</span>
          <span>Interactive Preview</span>
        </div>
        <div className="text-center text-sm font-medium text-slate-700">
          {title}
        </div>
        <div className="text-center text-xs text-slate-500 mb-2">
          by {author}
        </div>

        {/* Book spread */}
        <Spread leftPage={leftPage} rightPage={rightPage} />

        {/* Controls */}
        <div className="flex items-center justify-between mt-2 mb-4">
          <button
            onClick={handlePrev}
            disabled={!canPrev}
            className={`inline-flex items-center text-xs md:text-sm px-3 py-1.5 rounded-md border ${
              canPrev
                ? 'border-slate-200 text-slate-700 hover:bg-slate-50'
                : 'border-slate-100 text-slate-300 cursor-default'
            }`}
          >
            ‹ Previous
          </button>

          <div className="flex items-center gap-1">
            {Array.from({ length: totalSpreads }).map((_, i) => (
              <span
                key={i}
                className={`w-1.5 h-1.5 rounded-full ${
                  i === spreadIndex ? 'bg-slate-900' : 'bg-slate-300'
                }`}
              />
            ))}
          </div>

          <button
            onClick={handleNext}
            disabled={!canNext}
            className={`inline-flex items-center text-xs md:text-sm px-3 py-1.5 rounded-md border ${
              canNext
                ? 'border-slate-200 text-slate-700 hover:bg-slate-50'
                : 'border-slate-100 text-slate-300 cursor-default'
            }`}
          >
            Next ›
          </button>
        </div>

        {/* Progress bar */}
        <div className="mt-2 mb-6">
          <div className="w-full h-1.5 bg-slate-100 rounded-full overflow-hidden mb-1">
            <div
              className="h-1.5 bg-blue-600 transition-all"
              style={{ width: `${progress}%` }}
            />
          </div>
          <div className="text-[11px] text-slate-500 text-right">
            {progress}% complete
          </div>
        </div>

        {/* Bottom details */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8 text-sm text-slate-700">
          <div>
            <div className="font-semibold mb-2">Format Details</div>
            <ul className="text-xs text-slate-500 space-y-1">
              <li>• PDF/X-1a compliant</li>
              <li>• Embedded fonts</li>
              <li>• Print-ready margins</li>
            </ul>
          </div>
          <div>
            <div className="font-semibold mb-2">Specifications</div>
            <ul className="text-xs text-slate-500 space-y-1">
              <li>• Size: {trim}" trim</li>
              <li>• Typography: {typography}</li>
              <li>• Layout: {layout}</li>
            </ul>
          </div>
        </div>

        {/* Actions */}
        <div className="mt-6 flex flex-wrap items-center gap-3">
          <button className="inline-flex items-center px-4 py-2 rounded-md bg-blue-600 text-white text-xs md:text-sm font-medium">
            ⬇️ Download KDP File
          </button>
          <button className="inline-flex items-center px-3 py-2 rounded-md border border-slate-200 text-xs text-slate-600 hover:bg-slate-50">
            ⟳ Regenerate
          </button>
        </div>
      </div>
    </div>
  );
};

export default PreviewStep;
